__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc,
    __local int* localDst,
    __global int* outputBuffer)
{
    int n = get_global_id(0);
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Load src into local memory
    if (n < cols) {
        localSrc[local_id] = src[n];
    } else {
        localSrc[local_id] = INT_MAX;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < pyramid_height && (t + i) < (rows - 1); i++) {
        int idx = n;
        if (idx < cols) {
            int min_val = localSrc[local_id];
            if (local_id > 0)
                min_val = min(min_val, localSrc[local_id - 1]);
            if (local_id < local_size - 1)
                min_val = min(min_val, localSrc[local_id + 1]);
            int wall_val = wall[(t + i + 1) * cols + idx];
            localDst[local_id] = wall_val + min_val;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap localSrc and localDst pointers
        __local int* temp = localSrc;
        localSrc = localDst;
        localDst = temp;
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write final results to dst
    if (n < cols) {
        dst[n] = localSrc[local_id];
    }
}
